import redis
from typing import Dict, Any

class RedisCache:
    def __init__(self, host: str, port: int, password: str):
        self.redis_client = redis.Redis(host=host, port=port, db=0, decode_responses=True)
        self.redis_client.ping()
        self.password = password
        self.ttl_values = {
            'session_tokens': 3600,
            'api_keys': 86400
        }

    def set(self, key: str, value: Any, ttl_key: str):
        if ttl_key in self.ttl_values:
            ttl = self.ttl_values[ttl_key]
        else:
            ttl = None

        self.redis_client.set(key, value)
        if ttl is not None:
            self.redis_client.expire(key, ttl)

    def get(self, key: str) -> Any:
        return self.redis_client.get(key)

    def delete(self, key: str):
        self.redis_client.delete(key)


class RedisCluster:
    def __init__(self, nodes: Dict[str, int], password: str):
        self.nodes = nodes
        self.password = password

    def get_redis_client(self) -> redis.Redis:
        clients = []
        for node in self.nodes:
            client = redis.Redis(host=node['host'], port=node['port'], db=0, decode_responses=True)
            if not client.ping():
                print(f"Failed to connect to {node['host']}:{node['port']}")
                return None
            clients.append(client)

        return redis.cluster.StartCluster(clients, password=self.password)


